import { api } from "@/services/api-client";
import type { ApiListPayload, Ticket, TicketDetail, TicketMessage } from "@/types/domain";

export const ticketsService = {
  async list(page = 1, pageSize = 20) {
    const { data } = await api.get<ApiListPayload<Ticket>>("/tickets", {
      params: {
        page,
        page_size: pageSize,
      },
    });
    return data;
  },
  async detail(ticketId: number) {
    const { data } = await api.get<TicketDetail>(`/tickets/${ticketId}`);
    return data;
  },
  async create(payload: {
    subject: string;
    body: string;
    category?: string;
    priority?: string;
  }) {
    const { data } = await api.post<Ticket>("/tickets", payload);
    return data;
  },
  async reply(ticketId: number, body: string) {
    const { data } = await api.post<TicketMessage>(`/tickets/${ticketId}/reply`, { body });
    return data;
  },
  async resolve(ticketId: number, resolutionSummary: string) {
    const { data } = await api.post(`/tickets/${ticketId}/resolve`, {
      resolution_summary: resolutionSummary,
    });
    return data;
  },
  async close(ticketId: number) {
    const { data } = await api.post(`/tickets/${ticketId}/close`);
    return data;
  },
  async rate(ticketId: number, rating: number) {
    const { data } = await api.post(`/tickets/${ticketId}/rate`, { rating });
    return data;
  },
};
